This C code compiles without warnings but sometimes produces different outputs on different optimization levels (-O0 vs -O2). The behavior is non-deterministic. Find ALL sources of undefined behavior and explain what the compiler is allowed to do with each.

```c
#include <stdio.h>
#include <limits.h>

int main() {
    int x = INT_MAX;
    x = x + 1;  // Line A
    printf("%d\n", x);

    int arr[5] = {1, 2, 3, 4, 5};
    int y = arr[5];  // Line B

    int *p = NULL;
    if (p != NULL && *p == 42)  // Line C
        printf("found\n");

    int a = 1;
    int b = a++ + a++;  // Line D
    printf("%d\n", b);

    char *s = "hello";
    s[0] = 'H';  // Line E

    return 0;
}
